export function refreshDeviceToken(
  mobile: number | null | string,
  country: string | null,
  flag: string | null
) {
  if (mobile) localStorage.setItem('ludo_refresh_device_token_mobile', `${mobile}` || '')
  if (country) localStorage.setItem('ludo_refresh_device_token_country', `${country}` || '')
  if (flag) localStorage.setItem('ludo_refresh_device_token_flag', `${flag}` || '')

  const host = 'sawaludo'
  let href = location.href
  href = setUrlParams2('is_refresh', 1)
  href = `${host}://refresh_device_token/?url=${encodeURIComponent(href)}`
  console.warn('refreshDeviceToken', href)
  router(href)
}

export function getSub(access_token: string) {
  const arr = access_token.split('.')
  if (arr.length < 3) {
    return ''
  }
  try {
    const obj = arr[1]
    const subs = atob(obj)
    const o = JSON.parse(subs)
    const sub = o.sub
    return sub
  } catch (e) {
    return ''
  }
}

export function showBanToast(d: string) {
  const dd = Number(d)
  if (dd) {
    if (dd === -1) {
      showToast(_T('因涉嫌违规，你的账号被永久封禁。你无法再登录该账号。'))
    } else {
      const target = dayjs(dd * 1000)
        .utcOffset(3)
        .format('YYYY-MM-DD')
      showToast(
        sprintf(_T('因涉嫌违规，你的账号被封禁至{date}，这段时间内你将无法登陆该账号。'), {
          date: target,
        })
      )
    }
  }
}

export function getAppClientVersion() {
  const version_code = getArgsFromUrl('version_code')
  if (!version_code) return ''
  if (version_code.split('.').length !== 3) return version_code
  const [a, b, c] = version_code.split('.')
  const bb = b.length < 2 ? `0${b}` : b
  const cc = c.length < 2 ? `0${c}` : c
  return [a, bb, cc].join('')
}

