function resolveApiBase() {
  const base = getArgsFromUrl('api_base')
  if (base) {
    const v = decodeURIComponent(decodeURIComponent(base))
    const u = new URL(v).host
    const u2 = u.slice(-1) === '/' ? u : `${u}/`
    return `${new URL(v).protocol}//${u2}`
  }
  return process.env.VUE_APP_ENV === 'development' || getArgsFromUrl('is_debug')
    ? 'https://test03-pk.badambiz.com/'
    : 'https://arab-pk.badambiz.com/'
}
console.log('api_base:', resolveApiBase())
api.getAxiosInstance().defaults.baseURL = resolveApiBase()
