export function loginWithApple(
  user_id: string,
  access_token: string,
  nickname?: string,
  auto_create = false
) {
  const auth_access = store.state.data
  const uuid = getArgsFromUrl('uuid') || ''
  const bundle_id = getArgsFromUrl('bundle_id') || ''
  const obj: any = {
    login_type: 'apple',
    user_id,
    access_token,
    // nickname,
    auth_type: 1,
    auth_access,
    auto_create,
  }
  let data: any = new URLSearchParams()
  obj && Object.keys(obj).forEach((key) => data.append(key, obj[key]))
  // data = qs.stringify(data)

  return post('/api/user_mode/get_login_key/', data, {
    'x-cli-br': 1,
    'x-cli-id': uuid,
    'x-cli-pn': bundle_id,
    'x-cli-ve': getAppClientVersion(),
    'content-type': 'application/x-www-form-urlencoded',
  } as any) as Promise<[boolean, ApiResult<any>]>
}

